// noteInitSignals seeds the page-local signal bag. Kept OUT of the global
// InitialSignals bag so note_body (which can be large) doesn't ride every
// unrelated request. _-prefixed signals are FE-only (never posted).
func noteInitSignals(n NoteView) string {
	vis := "private"
	if n.IsPublic {
		vis = "public"
	}
	// Default to reading mode; open the editor up-front only for a fresh, empty
	// note (nothing to read yet — you came here to write). Existing notes open
	// collapsed: the work is reading + inline commenting.
	edit := "false"
	if n.Body == "" {
		edit = "true"
	}
	return `{"note_title":` + strconv.Quote(n.Title) +
		`,"note_visibility":` + strconv.Quote(vis) +
		`,"note_body":` + strconv.Quote(n.Body) +
		`,"note_c_block":"0","note_c_quote":"","note_c_body":"","note_share_channel":"","note_patch":"","note_cursor":0,` +
		`"note_req_msg":"",` +
		`"_note_canon":"","_note_ver":0,"_note_cursors":"[]","_note_req_busy":false,` +
		`"_note_share_open":false,"_note_comment_open":false,"_note_edit":` + edit + `,"_note_live":false}`
}

